class Rum():

  def __init__(self, storlek, fönster, uthyrt=False):
    self.storlek = storlek
    self.antal_fönster = fönster
    self.uthyrt = uthyrt

  def __str__(self):
    if self.uthyrt:
      sträng = "Rummet är uthyrt: "
    else:
      sträng = "Rummet är ledigt: "

    return sträng + str(self.storlek) + " kvm stort och har " + str(self.antal_fönster) + " fönster."

  def hyr_ut(self):
    self.uthyrt = True

  def är_ledigt(self):
    self.uthyrt = False

from rum import *

class Rum_med_Pentry(Rum):

  def __init__(self, storlek, fönster, uthyrt, ugn, micro):
   super().__init__(storlek, fönster, uthyrt)
   self.ugn = ugn
   self.micro = micro

  def __str__(self):
    if self.uthyrt:
      sträng = "Rummet är uthyrt: "
    else:
      sträng = "Rummet är ledigt: "

    if self.ugn:
      slut = ", har ugn och "
    else:
      slut = ", har inte ugn och "

    if self.micro:
      slut += "har micro."
    else:
      slut += "har inte micro."

    return sträng + str(self.storlek) + " kvm stort och har " + str(self.antal_fönster)\
           + " fönster" + slut
